# Generated by openai (gpt-5.4)
# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from fastapi import FastAPI, HTTPException, Query
from fastapi.responses import FileResponse
from pydantic import BaseModel
from typing import List, Optional, Literal
import os
import mimetypes
from datetime import datetime

app = FastAPI(title="File Explorer API")

USER_ROOTS = {
    "demo": os.path.abspath("./uploads/demo"),
}

os.makedirs(USER_ROOTS["demo"], exist_ok=True)


class FileEntry(BaseModel):
    name: str
    path: str
    type: Literal["file", "directory"]
    size: Optional[int] = None


class DirectoryListResponse(BaseModel):
    path: str
    entries: List[FileEntry]


class FileInfoResponse(BaseModel):
    name: str
    path: str
    type: Literal["file", "directory"]
    size: int
    mime_type: Optional[str] = None
    created_at: str
    modified_at: str


def get_user_root(user_id: str) -> str:
    root = USER_ROOTS.get(user_id)
    if not root:
        raise HTTPException(status_code=404, detail="User root not found")
    return root


def resolve_user_path(user_id: str, relative_path: str) -> str:
    root = get_user_root(user_id)
    relative_path = relative_path or "."
    normalized_relative = os.path.normpath(relative_path)
    full_path = os.path.normpath(os.path.join(root, normalized_relative))
    root_abs = os.path.abspath(root)
    full_abs = os.path.abspath(full_path)

    try:
        common = os.path.commonpath([root_abs, full_abs])
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid path")

    if common != root_abs:
        raise HTTPException(status_code=403, detail="Path escapes user root")

    return full_abs


@app.get("/files/list", response_model=DirectoryListResponse)
def list_directory(
    user_id: str = Query(...),
    path: str = Query(".", description="Path relative to the user's root directory"),
):
    full_path = resolve_user_path(user_id, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail="Path not found")
    if not os.path.isdir(full_path):
        raise HTTPException(status_code=400, detail="Path is not a directory")

    entries = []
    try:
        for name in sorted(os.listdir(full_path)):
            entry_full = os.path.join(full_path, name)
            rel_path = os.path.relpath(entry_full, get_user_root(user_id))
            is_dir = os.path.isdir(entry_full)
            size = None if is_dir else os.path.getsize(entry_full)
            entries.append(
                FileEntry(
                    name=name,
                    path="." if rel_path == "." else rel_path.replace("\\", "/"),
                    type="directory" if is_dir else "file",
                    size=size,
                )
            )
    except OSError:
        raise HTTPException(status_code=500, detail="Unable to read directory")

    normalized_path = os.path.normpath(path or ".").replace("\\", "/")
    return DirectoryListResponse(path=normalized_path, entries=entries)


@app.get("/files/download")
def download_file(
    user_id: str = Query(...),
    path: str = Query(..., description="File path relative to the user's root directory"),
):
    full_path = resolve_user_path(user_id, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail="File not found")
    if not os.path.isfile(full_path):
        raise HTTPException(status_code=400, detail="Path is not a file")

    return FileResponse(full_path, filename=os.path.basename(full_path))


@app.get("/files/info", response_model=FileInfoResponse)
def get_file_info(
    user_id: str = Query(...),
    path: str = Query(..., description="Path relative to the user's root directory"),
):
    full_path = resolve_user_path(user_id, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail="Path not found")

    stat_result = os.stat(full_path)
    is_dir = os.path.isdir(full_path)
    mime_type, _ = mimetypes.guess_type(full_path)

    rel_path = os.path.relpath(full_path, get_user_root(user_id)).replace("\\", "/")

    return FileInfoResponse(
        name=os.path.basename(full_path),
        path="." if rel_path == "." else rel_path,
        type="directory" if is_dir else "file",
        size=stat_result.st_size,
        mime_type=None if is_dir else mime_type,
        created_at=datetime.fromtimestamp(stat_result.st_ctime).isoformat(),
        modified_at=datetime.fromtimestamp(stat_result.st_mtime).isoformat(),
    )